// React Hooks for Captivate

// When called as a module like this, the ServiceHandler module loads qwebchannel internally
import { ServiceHandler } from './servicehandler.mjs';
import { QWebChannel } from './qwebchannel.mjs';

let scheduler = null;

// Initialize the ServiceHandler scheduler and return it.
// If it's already initialized, return the existing scheduler.
async function getServiceHandler() {
  if (scheduler) {
    return Promise.resolve(scheduler);
  }

  if (ServiceHandler) {
    const s = ServiceHandler;
    return new Promise((resolve) => {
      s.onready = () => {
        scheduler = s.scheduler;
        resolve(scheduler);
      };
      s.onclose = () => {
        console.warn('ServiceHandler connection closed. Cannot send data to Captivate.');
        scheduler = null;
      };
      s.init();
    });
  }
  return null;
}

async function sendVariablesToCaptivate(variables) {
  if (!scheduler) {
    await getServiceHandler();
  }
  if (!scheduler) {
    console.warn('ServiceHandler scheduler is not available. Is it running? If so, try again.');
    return;
  }
  return scheduler.scheduleAction('update', ServiceHandler.inputName, '', variables);
}

// New function for sending render commands for next round preparation
async function sendRenderCommand(variables) {
  if (!scheduler) {
    await getServiceHandler();
  }
  if (!scheduler) {
    console.warn('ServiceHandler scheduler is not available. Is it running? If so, try again.');
    return;
  }

  // Use the render action to prepare graphics ahead of time
  return scheduler.scheduleAction('render', ServiceHandler.inputName, '', variables);
}

// New function for sending curate commands if needed
async function sendCurateCommand(itemList) {
  if (!scheduler) {
    await getServiceHandler();
  }
  if (!scheduler) {
    console.warn('ServiceHandler scheduler is not available. Is it running? If so, try again.');
    return;
  }

  // Use the curate command to prepare a list of items
  return scheduler.scheduleAction('curate', ServiceHandler.inputName, '', { items: itemList });
}

export { getServiceHandler, sendVariablesToCaptivate, sendRenderCommand, sendCurateCommand };
